$data = Get-Content $file -Raw | ConvertFrom-Json

$p13 = [PSCustomObject]@{
    id = "REG-13"
    code = @{ ar = "REG-13"; en = "REG-13"; es = "REG-13"; it = "REG-13"; pt = "REG-13" }
    name = @{ ar = "امتداد الكنائس السبعة التاريخية"; en = "Seven Churches Extension"; es = "Extensión 7 Iglesias"; it = "Estensione 7 Chiese"; pt = "Extensão 7 Igrejas" }
    duration = @{ ar = "3 أيام / ليلتان"; en = "3 days / 2 nights"; es = "3 días / 2 noches"; it = "3 giorni / 2 notti"; pt = "3 dias / 2 noites" }
    minPax = @{ ar = "4 أفراد"; en = "4 Pax"; es = "4 Pax"; it = "4 Pax"; pt = "4 Pax" }
    overview = @{
        ar = "رحلة ثقافية ودينية متعمقة موجهة لعشاق التاريخ القديم والآثار التوراتية والمسيحية المبكرة. تأخذك عبر أطلال مدن آسيا الصغرى الرومانية القديمة لاستكشاف مواقع الكنائس السبعة التي وردت في سفر الرؤيا."
        en = "An in-depth cultural and religious journey aimed at lovers of ancient history and early Christian biblical archaeology. It takes you through the ruins of ancient Roman Asia Minor cities to explore the sites of the Seven Churches mentioned in the Book of Revelation."
        es = "Un viaje cultural y religioso en profundidad dirigido a los amantes de la historia antigua y la arqueología bíblica y cristiana primitiva. Te lleva a través de las ruinas de las antiguas ciudades romanas de Asia Menor para explorar los sitios de las Siete Iglesias mencionadas en el libro del Apocalipsis."
        it = "Un viaggio culturale e religioso approfondito rivolto agli amanti della storia antica e dell'archeologia biblica e paleocristiana. Ti porta attraverso le rovine delle antiche città romane dell'Asia Minore per esplorare i siti delle Sette Chiese menzionate nel libro dell'Apocalisse."
        pt = "Uma viagem cultural e religiosa aprofundada voltada para os amantes da história antiga e da arqueologia bíblica e cristã primitiva. Leva você através das ruínas das antigas cidades romanas da Ásia Menor para explorar os locais das Sete Igrejas mencionadas no livro do Apocalipse."
    }
    highlights = @{
        ar = @("زيارة أطلال مدينة ""ثياتيرا"" القديمة الشهيرة بصناعة الصبغات الأرجوانية الملكية.","صعود أكروبوليس برغامة ومشاهدة المسرح الأكثر انحداراً في العالم وبقايا مذبح زيوس العظيم.","استكشاف البازيليكا الحمراء الضخمة المبنية من الطوب الأحمر والمعروفة بكنيسة برغامة.","زيارة الكنيس اليهودي الأثري ومعبد الإلهة أرتيميس في مدينة ساردس التاريخية.")
        en = @("Visit the ruins of the ancient city of Thyatira, famous for its royal purple dye industry.","Climb the Pergamon Acropolis and see the steepest theater in the world and the remains of the great Altar of Zeus.","Explore the massive Red Basilica built of red brick, known as the Church of Pergamon.","Visit the ancient Jewish synagogue and the Temple of Artemis in the historic city of Sardis.")
        es = @("Visitar las ruinas de la antigua ciudad de Tiatira, famosa por su industria de tintes púrpura real.","Ascender al Acrópolis de Pérgamo y contemplar el teatro más empinado del mundo y los restos del gran Altar de Zeus.","Explorar la enorme Basílica Roja construida de ladrillo rojo, conocida como la Iglesia de Pérgamo.","Visitar la antigua sinagoga judía y el Templo de Artemisa en la histórica ciudad de Sardes.")
        it = @("Visitare le rovine dell'antica città di Tiatira, famosa per la sua industria di tinture porpora reale.","Salire sull'Acropoli di Pergamo e ammirare il teatro più ripido del mondo e i resti del grande Altare di Zeus.","Esplorare la massiccia Basilica Rossa costruita in mattoni rossi, conosciuta come la Chiesa di Pergamo.","Visitare l'antica sinagoga ebraica e il Tempio di Artemide nella storica città di Sardi.")
        pt = @("Visitar as ruínas da antiga cidade de Tiatira, famosa por sua indústria de tintura púrpura real.","Subir à Acrópole de Pérgamo e ver o teatro mais íngreme do mundo e os restos do grande Altar de Zeus.","Explorar a maciça Basílica Vermelha construída em tijolo vermelho, conhecida como a Igreja de Pérgamo.","Visitar a antiga sinagoga judaica e o Templo de Ártemis na histórica cidade de Sárdis.")
    }
    days = @(
        @{ day = "1"; meals = @{ ar = "عشاء"; en = "Dinner"; es = "Cena"; it = "Cena"; pt = "Jantar" }; description = @{ ar = "التحرك من كوشاداسي لزيارة مدينة ""ثياتيرا"" (أخيسار) ورؤية آثار البازيليكا البيزنطية، ثم التوجه لمدينة برغامة الأثرية وزيارة الأكروبوليس والمقابر الأثرية والبازيليكا الحمراء، والمبيت في إزمير."; en = "Depart from Kuşadası to visit the city of Thyatira (Akhisar) and see the remains of the Byzantine basilica, then proceed to the ancient city of Pergamon to visit the Acropolis, archaeological tombs, and the Red Basilica. Overnight in Izmir."; es = "Salida de Kuşadası para visitar la ciudad de Tiatira (Akhisar) y ver los restos de la basílica bizantina, luego continuar a la antigua ciudad de Pérgamo para visitar el Acrópolis, las tumbas arqueológicas y la Basílica Roja. Alojamiento en Esmirna."; it = "Partenza da Kuşadası per visitare la città di Tiatira (Akhisar) e vedere i resti della basilica bizantina, poi proseguire per l'antica città di Pergamo per visitare l'Acropoli, le tombe archeologiche e la Basilica Rossa. Pernottamento a Smirne."; pt = "Partida de Kuşadası para visitar a cidade de Tiatira (Akhisar) e ver os restos da basílica bizantina, depois seguir para a antiga cidade de Pérgamo para visitar a Acrópole, as tumbas arqueológicas e a Basílica Vermelha. Pernoitada em Esmirna." } }
        @{ day = "2"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "جولة في إزمير (موقع كنيسة سانت بوليكاربوس)، ثم التوجه لزيارة ""ساردس"" (عاصمة ليديا القديمة) وتشمل الأغورا، الجيمناسيوم، الكنيس، ومعبد أرتيميس، وختاماً بزيارة كنيسة القديس يوحنا في فيلادلفيا، ثم العشاء والمبيت."; en = "Tour of Izmir (site of the Church of St. Polycarp), then proceed to visit Sardis (capital of ancient Lydia) including the Agora, Gymnasium, Synagogue, and Temple of Artemis, ending with a visit to the Church of St. John in Philadelphia. Dinner and overnight."; es = "Recorrido por Esmirna (sitio de la Iglesia de San Policarpo), luego visita a Sardes (capital de la antigua Lidia) incluyendo el Ágora, el Gimnasio, la Sinagoga y el Templo de Artemisa, finalizando con la visita a la Iglesia de San Juan en Filadelfia. Cena y alojamiento."; it = "Giro di Smirne (sito della Chiesa di San Policarpo), poi visita a Sardi (capitale dell'antica Lidia) inclusi Agorà, Ginnasio, Sinagoga e Tempio di Artemide, terminando con la visita alla Chiesa di San Giovanni a Filadelfia. Cena e pernottamento."; pt = "Tour por Esmirna (local da Igreja de São Policarpo), depois visita a Sárdis (capital da antiga Lídia) incluindo a Ágora, o Ginásio, a Sinagoga e o Templo de Ártemis, terminando com a visita à Igreja de São João na Filadélfia. Jantar e pernoite." } }
        @{ day = "3"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "زيارة لاوديكيا، ثم النقل إلى ميناء كوشاداسي أو إلى مطار إزمير للمغادرة."; en = "Visit Laodicea, then transfer to Kuşadası port or Izmir airport for departure."; es = "Visita a Laodicea, luego traslado al puerto de Kuşadası o al aeropuerto de Esmirna para la salida."; it = "Visita a Laodicea, poi trasferimento al porto di Kuşadası o all'aeroporto di Smirne per la partenza."; pt = "Visita a Laodicéia, depois transfer para o porto de Kuşadası ou aeroporto de Esmirna para partida." } }
    )
}

$p14 = [PSCustomObject]@{
    id = "REG-14"
    code = @{ ar = "REG-14"; en = "REG-14"; es = "REG-14"; it = "REG-14"; pt = "REG-14" }
    name = @{ ar = "سر المعبد والشرق الأناضولي"; en = "Secret of the Temple & Eastern Anatolia"; es = "Secreto del Templo"; it = "Segreto del Tempio"; pt = "Segredo do Templo" }
    duration = @{ ar = "11 يوماً / 10 ليالٍ"; en = "11 days / 10 nights"; es = "11 días / 10 noches"; it = "11 giorni / 10 notti"; pt = "11 dias / 10 noites" }
    minPax = @{ ar = "4 أفراد"; en = "4 Pax"; es = "4 Pax"; it = "4 Pax"; pt = "4 Pax" }
    overview = @{
        ar = "هذه ليست مجرد رحلة، بل هي ""بعثة استكشافية"" إلى بلاد الرافدين ومنطقة مهد الحضارات الإنسانية في جنوب شرق تركيا. برنامج استثنائي يبتعد عن المسارات التقليدية ليأخذ المسافرين الشغوفين إلى نقطة الصفر في التاريخ، ومزارات الأنبياء، والبلدات التي لا تزال تتحدث لغة السيد المسيح الآرامية."
        en = "This is not just a trip, but an ""exploratory expedition"" to Mesopotamia and the cradle of human civilization in southeastern Turkey. An exceptional program that moves away from traditional routes to take passionate travelers to ground zero of history, the shrines of prophets, and towns that still speak the Aramaic language of Jesus Christ."
        es = "Esto no es solo un viaje, sino una ""expedición exploratoria"" a Mesopotamia y la cuna de las civilizaciones humanas en el sureste de Turquía. Un programa excepcional que se aleja de las rutas tradicionales para llevar a los viajeros apasionados al punto cero de la historia, los santuarios de los profetas y los pueblos que aún hablan la lengua aramea de Jesucristo."
        it = "Questo non è solo un viaggio, ma una ""spedizione esplorativa"" in Mesopotamia e nella culla delle civiltà umane nel sud-est della Turchia. Un programma eccezionale che si allontana dalle rotte tradizionali per portare i viaggiatori appassionati al punto zero della storia, ai santuari dei profeti e ai paesi che parlano ancora la lingua aramaica di Gesù Cristo."
        pt = "Esta não é apenas uma viagem, mas uma ""expedição exploratória"" à Mesopotâmia e ao berço das civilizações humanas no sudeste da Turquia. Um programa excepcional que se afasta das rotas tradicionais para levar viajantes apaixonados ao ponto zero da história, aos santuários dos profetas e às cidades que ainda falam a língua aramaica de Jesus Cristo."
    }
    highlights = @{
        ar = @("رؤية فسيفساء ""الفتاة الغجرية"" الشهيرة عالمياً في متحف زيوغما بمدينة غازي عنتاب.","صعود جبل نمرود التاريخي بين التماثيل الحجرية العملاقة لمشاهدة شروق شمس لا يُنسى.","زيارة الكهف التاريخي لولادة سيدنا إبراهيم عليه السلام والبحيرات الأثرية في أورفا.","الدخول الحصري لموقع غوبكلي تبه (Göbeklitepe)، أقدم معبد شيده البشر في التاريخ قبل 12,000 عام.","زيارة دير مار غبريال في ماردين وسماع الصلوات باللغة الآرامية القديمة الأصلية.","استكشاف صهاريج مياه مدينة ""دارا"" الصخرية الأسطورية الملقبة بـ ""أفسس بلاد الرافدين"".")
        en = @("See the world-famous ""Gypsy Girl"" mosaic at the Zeugma Museum in Gaziantep.","Climb historic Mount Nemrud among giant stone statues for an unforgettable sunrise.","Visit the cave where Prophet Abraham was born and the archaeological lakes in Urfa.","Exclusive entry to Göbeklitepe, the oldest temple built by mankind 12,000 years ago.","Visit Mor Gabriel Monastery in Mardin and hear prayers in the ancient Aramaic language.","Explore the legendary rock-cut water cisterns of the city of Dara, known as the ""Ephesus of Mesopotamia.""")
        es = @("Ver el mundialmente famoso mosaico de la ""Niña Gitana"" en el Museo de Zeugma en Gaziantep.","Ascender al histórico Monte Nemrud entre estatuas de piedra gigantes para ver un amanecer inolvidable.","Visitar la cueva donde nació el Profeta Abraham y los lagos arqueológicos en Urfa.","Entrada exclusiva a Göbeklitepe, el templo más antiguo construido por la humanidad hace 12.000 años.","Visitar el Monasterio Mor Gabriel en Mardin y escuchar oraciones en la antigua lengua aramea.","Explorar las legendarias cisternas de agua excavadas en la roca de la ciudad de Dara, conocida como la ""Éfeso de Mesopotamia"".")
        it = @("Vedere il famoso mosaico della ""Ragazza Zingara"" al Museo di Zeugma a Gaziantep.","Salire sul storico Monte Nemrud tra statue di pietra giganti per un'alba indimenticabile.","Visitare la grotta dove nacque il Profeta Abramo e i laghi archeologici a Urfa.","Ingresso esclusivo a Göbeklitepe, il tempio più antico costruito dall'umanità 12.000 anni fa.","Visitare il Monastero Mor Gabriel a Mardin e ascoltare preghiere nell'antica lingua aramaica.","Esplorare le leggendarie cisterne d'acqua scavate nella roccia della città di Dara, conosciuta come l'""Efeso della Mesopotamia"".")
        pt = @("Ver o mundialmente famoso mosaico da ""Garota Cigana"" no Museu de Zeugma em Gaziantep.","Subir o histórico Monte Nemrud entre estátuas de pedra gigantes para um nascer do sol inesquecível.","Visitar a caverna onde o Profeta Abraão nasceu e os lagos arqueológicos em Urfa.","Entrada exclusiva em Göbeklitepe, o templo mais antigo construído pela humanidade há 12.000 anos.","Visitar o Mosteiro Mor Gabriel em Mardin e ouvir orações na antiga língua aramaica.","Explorar as lendárias cisternas de água escavadas na rocha da cidade de Dara, conhecida como a ""Éfeso da Mesopotâmia"".")
    }
    days = @(
        @{ day = "1–5"; meals = $null; description = @{ ar = "تتطابق تماماً في مسارها البري والوجبات المحددة مع أول 5 أيام من مسار ""تركيا الأسطورية براً"" (إسطنبول، أنقرة، وديان كابادوكيا والمنطاد والمدن الأرضية)."; en = "Fully identical in overland route and specified meals to the first 5 days of the ""Legendary Turkey by Land"" itinerary (Istanbul, Ankara, Cappadocia valleys, hot air balloon, underground cities)."; es = "Totalmente idénticos en ruta terrestre y comidas especificadas a los primeros 5 días del itinerario de ""Turquía Legendaria por Tierra"" (Estambul, Ankara, valles de Capadocia, globo aerostático, ciudades subterráneas)."; it = "Completamente identici nel percorso via terra e nei pasti specificati ai primi 5 giorni dell'itinerario della ""Turchia Leggendaria via Terra"" (Istanbul, Ankara, valli della Cappadocia, mongolfiera, città sotterranee)."; pt = "Totalmente idênticos em rota terrestre e refeições especificadas aos primeiros 5 dias do itinerário ""Turquia Lendária por Terra"" (Istambul, Ancara, vales da Capadócia, balão de ar quente, cidades subterrâneas)." } }
        @{ day = "6"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "التحرك براً من كابادوكيا لمدينة غازي عنتاب (Antep)، وزيارة متحف زيوغما للموزاييك الروماني، ووقت حر والمبيت."; en = "Travel overland from Cappadocia to Gaziantep (Antep), visit the Zeugma Museum of Roman mosaics, free time, overnight."; es = "Traslado por carretera de Capadocia a Gaziantep (Antep), visita al Museo de Zeugma de mosaicos romanos, tiempo libre, alojamiento."; it = "Trasferimento via terra dalla Cappadocia a Gaziantep (Antep), visita al Museo di Zeugma dei mosaici romani, tempo libero, pernottamento."; pt = "Transferência terrestre da Capadócia para Gaziantep (Antep), visita ao Museu de Zeugma de mosaicos romanos, tempo livre, pernoite." } }
        @{ day = "7"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "زيارة قلعة عنتاب وبازارها القديم وتذوق البقلاوة التراثية، ثم التحرك لبلدة هالفيتي لرؤية منابت ""الورود السوداء"" النادرة، والتوجه إلى جبل نمرود للمبيت."; en = "Visit Gaziantep Castle and its old bazaar, taste traditional baklava, then proceed to Halfeti town to see the rare ""black roses,"" head to Mount Nemrud for overnight."; es = "Visitar el Castillo de Gaziantep y su antiguo bazar, degustar el baklava tradicional, luego ir al pueblo de Halfeti para ver las raras ""rosas negras,"" dirigirse al Monte Nemrud para alojamiento."; it = "Visitare il Castello di Gaziantep e il suo antico bazar, assaggiare il baklava tradizionale, poi proseguire per Halfeti per vedere le rare ""rose nere,"" dirigersi al Monte Nemrud per il pernottamento."; pt = "Visitar o Castelo de Gaziantep e seu antigo bazar, provar o baklava tradicional, depois seguir para a cidade de Halfeti para ver as raras ""rosas negras,"" ir ao Monte Nemrud para pernoite." } }
        @{ day = "8"; meals = @{ ar = "إفطار صندوقي + عشاء"; en = "Box Breakfast + Dinner"; es = "Desayuno de caja + Cena"; it = "Colazione al sacco + Cena"; pt = "Café da manhã de caixa + Jantar" }; description = @{ ar = "صعود جبل نمرود لمشاهدة التماثيل العملاقة لرؤوس الآلهة، والتحرك لمدينة أورفا وزيارة القلعة وبحيرة الأسماك وكهف ميلاد سيدنا إبراهيم، وكنيسة ريجي ومتحف أورفا الأثري (اختياري: حضور سهرة ليلة تيسير الموسيقية التراثية)."; en = "Climb Mount Nemrud to see the giant statues of the gods' heads, proceed to Urfa to visit the castle, fish lake, cave where Prophet Abraham was born, Church of Rıjı, and Urfa Archaeological Museum. (Optional: attend a traditional Sira music evening)."; es = "Ascender al Monte Nemrud para ver las estatuas gigantes de cabezas de dioses, ir a Urfa para visitar el castillo, el lago de los peces, la cueva del nacimiento del Profeta Abraham, la Iglesia de Rıjı y el Museo Arqueológico de Urfa. (Opcional: asistir a una velada musical tradicional de Sira)."; it = "Salire sul Monte Nemrud per vedere le statue giganti delle teste degli dei, proseguire per Urfa per visitare il castello, il lago dei pesci, la grotta della nascita del Profeta Abramo, la Chiesa di Rıjı e il Museo Archeologico di Urfa. (Opzionale: partecipare a una serata musicale tradizionale Sira)."; pt = "Subir ao Monte Nemrud para ver as estátuas gigantes das cabeças dos deuses, seguir para Urfa para visitar o castelo, o lago dos peixes, a caverna do nascimento do Profeta Abraão, a Igreja de Rıjı e o Museu Arqueológico de Urfa. (Opcional: assistir a uma noite musical tradicional Sira)." } }
        @{ day = "9"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "التحرك لبلدة حرّان لرؤية المنازل الطينية المقببة، وزيارة موقع غوبكلي تبه (Göbeklitepe) الأثري العالمي المدرج باليونسكو، والتحرك لمدينة ماردين والمبيت."; en = "Proceed to Harran to see the beehive mud-brick houses, visit the UNESCO-listed archaeological site of Göbeklitepe, then travel to Mardin for overnight."; es = "Ir a Harran para ver las casas de adobe con forma de colmena, visitar el sitio arqueológico de Göbeklitepe declarado Patrimonio de la UNESCO, luego viajar a Mardin para alojamiento."; it = "Proseguire per Harran per vedere le case di fango a forma di alveare, visitare il sito archeologico di Göbeklitepe patrimonio UNESCO, poi viaggiare a Mardin per il pernottamento."; pt = "Seguir para Harran para ver as casas de barro em forma de colmeia, visitar o sítio arqueológico de Göbeklitepe declarado Patrimônio da UNESCO, depois viajar para Mardin para pernoite." } }
        @{ day = "10"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "جولة في ماردين تشمل دير مار غبريال السرياني الأرثوذكسي الأقدم، وزيارة مدينة ""دارا"" الأثرية المحفورة في الصخور، ثم النقل لمطار ماردين للطيران عودة إلى إسطنبول لليلة الأخيرة."; en = "Tour of Mardin including the ancient Syriac Orthodox Mor Gabriel Monastery, visit the rock-carved ancient city of Dara, then transfer to Mardin airport to fly back to Istanbul for the last night."; es = "Recorrido por Mardin incluyendo el antiguo Monasterio Sirio Ortodoxo Mor Gabriel, visita a la antigua ciudad excavada en la roca de Dara, luego traslado al aeropuerto de Mardin para volar de regreso a Estambul para la última noche."; it = "Giro di Mardin incluso l'antico Monastero Siro Ortodosso Mor Gabriel, visita all'antica città scavata nella roccia di Dara, poi trasferimento all'aeroporto di Mardin per volare di ritorno a Istanbul per l'ultima notte."; pt = "Tour por Mardin incluindo o antigo Mosteiro Siríaco Ortodoxo Mor Gabriel, visita à antiga cidade escavada na rocha de Dara, depois transfer para o aeroporto de Mardin para voar de volta a Istambul para a última noite." } }
        @{ day = "11"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "التوصيل للمطار للمغادرة النهائية."; en = "Transfer to airport for final departure."; es = "Traslado al aeropuerto para la salida final."; it = "Trasferimento in aeroporto per la partenza finale."; pt = "Transfer para o aeroporto para partida final." } }
    )
}

$data.programs += $p13
$data.programs += $p14
$data | ConvertTo-Json -Depth 100 | Set-Content -Path $file -Encoding UTF8
Write-Host "Programs 13-14 added. Final size: $((Get-Item $file).Length) bytes"
Write-Host "Total programs: $($data.programs.Count)"
